def read_and_print_file(filepath):
    results = []
    with open(filepath, 'r') as file:
        for line in file:
            clean_line = line.strip()
            if clean_line.startswith('*') or clean_line.startswith('.'):
                continue
            parts = clean_line.split()
            results.append(parts)
    return results

